// // This ROM module outputs a 4-bit data value based on a 4-bit address input. On the falling edge of the clock, if the reset signal is deasserted, the output is set to zero. Otherwise, it retrieves specific pre-defined values corresponding to the address: for address 0, output 0; for address 1, output 1; and for address 2, output 2. For any other address, it defaults to output 3.
module top_module(
    addr,
    dout,
    clk,
    rst
);input [3:0] addr;
output [3:0] dout;
reg [3:0] dout;
input clk;
input rst;




always @(posedge clk) begin: ROMPARMLOADSYNC_READACTION
    if (rst) begin
        dout <= 0;
    end
    else begin
        case (addr)
            0: dout <= 3;
            1: dout <= 2;
            2: dout <= 1;
            default: dout <= 0;
        endcase
    end
end

endmodule
